import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { loginUser } from '../api/api';
import { useAuth } from '../context/AuthContext';

const Login = () => {
  const [form, setForm] = useState({ mail: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();
  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await loginUser(form);
      const userData = res.data.data;
      login(userData);
      toast.success(`Welcome back, ${userData.name}!`);
      navigate(userData.role === 'ADMIN' ? '/admin' : '/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally { setLoading(false); }
  };

  return (
    <div style={{
      minHeight:'100vh', display:'flex',
      background:'var(--bg-primary)',
    }}>
      {/* Left decorative panel */}
      <div style={{
        flex:1, display:'flex', flexDirection:'column', justifyContent:'center', alignItems:'center',
        background:'linear-gradient(135deg, #fff8f5 0%, #fef0e8 50%, #fde8d8 100%)',
        borderRight:'1.5px solid var(--border)',
        padding:'60px', position:'relative', overflow:'hidden',
      }}>
        <div style={{ position:'absolute', top:'-80px', right:'-80px', width:'320px', height:'320px', background:'rgba(224,92,42,0.06)', borderRadius:'50%' }} />
        <div style={{ position:'absolute', bottom:'-60px', left:'-60px', width:'240px', height:'240px', background:'rgba(224,92,42,0.04)', borderRadius:'50%' }} />
        <div style={{ position:'relative', textAlign:'center', maxWidth:'340px' }}>
          <div style={{ fontSize:'64px', marginBottom:'20px' }}>🎭</div>
          <h1 style={{ fontFamily:'var(--font-display)', fontSize:'2.8rem', color:'var(--text-primary)', marginBottom:'16px', lineHeight:1.2 }}>
            Book your<br /><span style={{ color:'var(--accent)' }}>perfect seat</span>
          </h1>
          <p style={{ color:'var(--text-muted)', fontSize:'15px', lineHeight:1.7 }}>
            Movies, concerts & live events — find your next unforgettable experience.
          </p>
          <div style={{ display:'flex', gap:'16px', justifyContent:'center', marginTop:'32px' }}>
            {['🎬 Movies','🎵 Concerts','🎪 Events'].map(t => (
              <span key={t} style={{ padding:'6px 14px', background:'white', borderRadius:'99px', fontSize:'13px', fontWeight:600, color:'var(--text-secondary)', border:'1.5px solid var(--border)', boxShadow:'var(--shadow-sm)' }}>{t}</span>
            ))}
          </div>
        </div>
      </div>

      {/* Right login form */}
      <div style={{ width:'440px', display:'flex', alignItems:'center', justifyContent:'center', padding:'40px', background:'var(--bg-card)' }}>
        <div style={{ width:'100%', maxWidth:'360px' }}>
          <div style={{ marginBottom:'36px' }}>
            <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'24px' }}>
              <div style={{ width:40, height:40, background:'var(--accent)', borderRadius:'10px', display:'flex', alignItems:'center', justifyContent:'center', boxShadow:'0 2px 8px rgba(224,92,42,0.3)' }}>
                <span style={{ fontFamily:'var(--font-display)', fontSize:'22px', color:'#fff' }}>S</span>
              </div>
              <span style={{ fontFamily:'var(--font-display)', fontSize:'1.4rem', color:'var(--text-primary)' }}>ShowSpot</span>
            </div>
            <h2 style={{ fontFamily:'var(--font-display)', fontSize:'2rem', fontWeight:400, color:'var(--text-primary)', marginBottom:'6px' }}>Welcome back</h2>
            <p style={{ color:'var(--text-muted)', fontSize:'14px' }}>Sign in to your account to continue</p>
          </div>

          <form onSubmit={submit}>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input name="mail" type="email" className="form-input" placeholder="you@example.com" value={form.mail} onChange={handle} required />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <input name="password" type="password" className="form-input" placeholder="Enter your password" value={form.password} onChange={handle} required />
            </div>
            <button type="submit" className="btn btn-primary btn-full btn-lg" disabled={loading} style={{ marginTop:'8px' }}>
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>
          </form>

          <div style={{ textAlign:'center', marginTop:'24px', padding:'20px 0', borderTop:'1px solid var(--border)' }}>
            <p style={{ fontSize:'14px', color:'var(--text-muted)' }}>
              Don't have an account?{' '}
              <Link to="/register" style={{ color:'var(--accent)', fontWeight:700 }}>Create one free</Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};
export default Login;
